{
  "semantic_mode": "refill_first",
  "lean": "theorem refill_before_consume (t: Time) (b: Bucket): refill t b -> consume t b -> ∀ t', t' = t -> tokens_after t' = tokens_before t' + refill_amount - consume_amount",
  "assumptions": [
    "refill and consume can occur at the same timestamp",
    "refill_amount and consume_amount are constants"
  ],
  "preconditions": [
    "bucket is initialized",
    "timestamp t is valid"
  ],
  "postconditions": [
    "tokens_after = tokens_before + refill_amount - consume_amount"
  ],
  "invariants": [
    "tokens >= 0",
    "tokens <= bucket_capacity"
  ],
  "examples": [
    {
      "initial_tokens": 5,
      "refill_amount": 3,
      "consume_amount": 4,
      "tokens_after": 4
    },
    {
      "initial_tokens": 2,
      "refill_amount": 5,
      "consume_amount": 3,
      "tokens_after": 4
    }
  ],
  "notes": [
    "Refill is applied before consumption at the same timestamp.",
    "This choice affects the available tokens for immediate consumption."
  ]
}
```

