{
  "semantic_mode": "inclusive",
  "lean": "def token_valid_at_expiry (token : Token) : Prop := token.expiry <= current_time",
  "assumptions": [
    "token: the token being validated",
    "current_time: the current time when validation is performed"
  ],
  "preconditions": [
    "token must have a defined expiry timestamp",
    "current_time must be defined"
  ],
  "postconditions": [
    "the token is considered valid at its expiry timestamp if the expiry time is less than or equal to the current time"
  ],
  "invariants": [
    "the validity of the token at expiry is determined solely by the comparison of expiry time and current time"
  ],
  "examples": [
    "Token with expiry at 10:00 AM, current time 10:00 AM => valid",
    "Token with expiry at 10:00 AM, current time 10:01 AM => invalid"
  ],
  "notes": [
    "This specification considers the token to be valid at the exact moment of its expiry",
    "The comparison is inclusive to ensure the token is valid until the exact expiry time"
  ]
}

{
  "semantic_mode": "inclusive",
  "lean": "def token_valid_at_expiry (token : Token) : Prop := token.expiry ≤ current_time",
  "assumptions": [
    "Token has an expiry timestamp",
    "Current time is known"
  ],
  "preconditions": [
    "Token is valid"
  ],
  "postconditions": [
    "Token is considered valid exactly at the expiry timestamp"
  ],
  "invariants": [
    "Token remains valid until the expiry timestamp inclusive"
  ],
  "examples": [
    "Token expires at 10:00:00, current time is 10:00:00 => token_valid_at_expiry(token) is true",
    "Token expires at 10:00:00, current time is 10:00:01 => token_valid_at_expiry(token) is false"
  ],
  "notes": [
    "The token is considered valid at the exact moment of expiry",
    "Inclusive boundary semantics are used for token expiry validation"
  ]
}

